function solve(value, limit) {
    const n = value.length;
    const indices = Array.from({ length: n }, (_, i) => i);
    indices.sort((a, b) => limit[a] - limit[b] || value[b] - value[a]);

    let total = 0;
    let activeCount = 0;
    let i = 0;

    while (i < n) {
        const currentLimit = limit[indices[i]];
        if (activeCount >= currentLimit) {
            i++;
            continue;
        }
        let j = i;
        let maxValue = -Infinity;
        let bestIndex = -1;
        while (j < n && limit[indices[j]] === currentLimit) {
            if (value[indices[j]] > maxValue) {
                maxValue = value[indices[j]];
                bestIndex = j;
            }
            j++;
