                        // Mark as processed by moving past them
                        if (k <= bestIndex) {
                            i++;
                        }
                    }
                }
            } else {
                i++;
            }
            // Swap the best to current i and increment i
            [indices[i], indices[bestIndex]] = [indices[bestIndex], indices[i]];
            i++;
        }
    }

    return total;
