    val indices = (0 until n).toArray
    // Sort by limit ascending, then by value descending
    scala.util.Sorting.stableSort(indices, (a: Int, b: Int) => {
        if (limit(a) < limit(b)) true
        else if (limit(a) > limit(b)) false
