        val currentLimit = limit(indices(i))
        if (activeCount >= currentLimit) {
            i += 1
        } else {
            // Find the best value in current limit group
            var j = i
            var maxValue = -1L
            var bestIndex = -1
            while (j < n && limit(indices(j)) == currentLimit) {
                if (value(indices(j)) > maxValue) {
                    maxValue = value(indices(j))
                    bestIndex = j
                }
                j += 1
            }
            if (bestIndex != -1) {
                total += value(indices(bestIndex))
                activeCount += 1
                // Swap best to current i
                val temp = indices(i)
                indices(i) = indices(bestIndex)
